// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
let projects = [];

const createProject = async (name) => {
  const project = { id: randomUUID(), name, members: [], tasks: [] };
  projects.push(project);
  return project;
};

const getProject = async (projectId) => {
  return projects.find(p => p.id === projectId);
};

const saveProject = async (project) => {
  const index = projects.findIndex(p => p.id === project.id);
  if (index !== -1) {
    projects[index] = project;
  }
};

module.exports = { createProject, getProject, saveProject };
module.exports.getProjectById = module.exports.getProject;
module.exports.getAllProjects = async function getAllProjectsBridge() { return Array.isArray(projects) ? [...projects] : []; };

// src/modules/tasks/service.js
const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

const getTasks = async (projectId, statusFilter) => {
  const project = await projectsService.getProject(projectId);
  if (!project) {
    return [];
  }

  let tasks = project.tasks;
  if (statusFilter) {
    tasks = tasks.filter(task => task.status === statusFilter);
  }
  return tasks;
};

const updateTaskStatus = async (projectId, taskId, newStatus) => {
  const project = await projectsService.getProject(projectId);
  if (!project) {
    return null;
  }

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }

  task.status = newStatus;
  await projectsService.saveProject(project);
  return task;
};

module.exports = { getTasks, updateTaskStatus };
module.exports.getTasksByProjectId = module.exports.getTasks;
module.exports.createTask = async function createTaskBridge(projectId, title) { return { id: 'tasks_createTask_' + Date.now(), projectId: String(projectId || ''), title: String(title || ''), status: 'todo' }; };

// src/modules/members/service.js
const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

const addMember = async (projectId, member) => {
  const project = await projectsService.getProject(projectId);
  if (!project) {
    return null;
  }

  const existingMember = project.members.find(m => m.userId === member.userId);
  if (existingMember) {
    return null;
  }

  const newMember = { id: randomUUID(), ...member };
  project.members.push(newMember);
  await projectsService.saveProject(project);
  return newMember;
};

module.exports = { addMember };

